#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::TextExtractor;

# Function to extract text from a PDF
sub extract_text {
    my ($file) = @_;
    my $pdf = PDF::API2->open($file);
    my $text = PDF::TextExtractor->new($pdf);

    my @pages;
    for (1..$pdf->pages) {
        my $page = $text->get_textblock($_);
        push @pages, $page;
    }

    return join("\n", @pages);
}

# Function to extract specific data
