    my $author = $text =~ /Author: ([^ ]+)/;
    my $table = $text =~ /Table\s+(\d+)/;

    return {
        date => $date ? $1 : 'Not Found',
        author => $author ? $1 : 'Not Found',
        table => $table ? $1 : 'Not Found',
    };
}

